const response = $input.first().json;
return [{
  json: {
    run_id: String(response.run_id),
    poll_count: 0
  }
}];

const statusData = $input.first().json;
const runId = $('Init Poll State').first().json.run_id;

// Poll count: self-reference for loop iterations, 0 on first pass
let prevCount = 0;
try {
  prevCount = $('Evaluate Status').first().json.poll_count;
} catch {
  // First iteration — node has no prior output yet
}

return [{
  json: {
    run_id: runId,
    poll_count: prevCount + 1,
    status: statusData.status ?? 'unknown',
    high_risk_count: statusData.high_risk_count ?? 0,
    transactions_scored: statusData.transactions_scored ?? 0,
    duplicates_found: statusData.duplicates_found ?? 0,
    started_at: statusData.started_at ?? null,
    completed_at: statusData.completed_at ?? null
  }
}];

const runData = $('Evaluate Status').first().json;
const transactions = $input.all().map(item => item.json);

const lines = [
  '\u{1F6A8} *LeakWatch Anomaly Alert*',
  '',
  '*Run Summary*',
  `\u2022 Run ID: \`${runData.run_id}\``,
  `\u2022 Completed: ${runData.completed_at || 'N/A'}`,
  `\u2022 Transactions Scored: ${(runData.transactions_scored || 0).toLocaleString()}`,
  `\u2022 High Risk Found: *${runData.high_risk_count}*`,
  `\u2022 Duplicates Found: ${runData.duplicates_found}`,
  '',
  `*Top ${transactions.length} High-Risk Transactions:*`
];

for (const txn of transactions) {
  const prob = (txn.leak_probability || 0).toFixed(3);
  const factors = (txn.risk_factors || []).join(', ') || 'none';
  const dup = txn.is_duplicate ? ` \u26A0\uFE0F DUP of ${txn.duplicate_of || '?'}` : '';
  lines.push(`\u2022 \`${txn.voucher_number}\` \u2014 P=${prob} [${factors}]${dup}`);
}

if (runData.high_risk_count > transactions.length) {
  lines.push('', `_\u2026and ${runData.high_risk_count - transactions.length} more. Review in dashboard._`);
}

lines.push('', '\u{1F449} Review immediately in the LeakWatch dashboard.');

return [{
  json: {
    text: lines.join('\n'),
    summary: `LeakWatch: ${runData.high_risk_count} high-risk transactions detected out of ${(runData.transactions_scored || 0).toLocaleString()} scored.`,
    severity: 'critical',
    source: 'leakwatch',
    run_id: runData.run_id,
    high_risk_count: runData.high_risk_count,
    transactions_scored: runData.transactions_scored,
    duplicates_found: runData.duplicates_found,
    top_transactions: transactions
  }
}];

